// Copyright Amazon.com, Inc. or its affiliates. All Rights Reserved.
// SPDX-License-Identifier: Apache-2.0
//! `Tagged`: the bit-stealing contract.
//!
//! A `Tagged` impl provides an injective encoding `(T, bool) -> Repr` so a
//! capture flag can be packed alongside the value. Two ghost spec functions
//! describe the encoding:
//!
//!   - `value_of(r) -> Self`         — the clean value embedded in `r`
//!   - `tag_of(r) -> bool`           — the tag bit embedded in `r`
//!
//! Concrete impls (e.g. `BoolPair<T>` for primitives, `DenseId<W>` over `u32`)
//! discharge round-trip axioms via the trait method contracts:
//!
//!   - `into_repr(t)`  has  `value_of(_) == t && tag_of(_) == false`
//!   - `from_repr(r)`  returns  `value_of(*r)`
//!   - `tag(r)`        returns  `tag_of(*r)`
//!   - `set_tag` / `clear_tag` flip `tag_of` while preserving `value_of`
//!
//! These axioms together guarantee that `view()` is invariant under capture-
//! flag edits, which is what `InlineStore` needs.

use vstd::prelude::*;

verus! {

/// Bit-stealing contract for values that can carry a tag bit alongside them.
pub trait Tagged: Sized + Copy {
    type Repr: Sized + Copy;

    // -- ghost projections ---------------------------------------------------

    /// The clean value embedded in `r`. Survives `set_tag`/`clear_tag`.
    spec fn value_of(r: Self::Repr) -> Self;

    /// The tag bit embedded in `r`.
    spec fn tag_of(r: Self::Repr) -> bool;

    // -- exec API ------------------------------------------------------------

    /// Encode a clean value with `tag = false`.
    fn into_repr(self) -> (r: Self::Repr)
        ensures
            Self::value_of(r) == self,
            Self::tag_of(r) == false;

    /// Decode a `Repr` to its clean value, stripping the tag.
    fn from_repr(r: &Self::Repr) -> (v: Self)
        ensures v == Self::value_of(*r);

    /// Read the tag bit.
    fn tag(r: &Self::Repr) -> (b: bool)
        ensures b == Self::tag_of(*r);

    /// Set the tag bit. Value is preserved.
    fn set_tag(r: &mut Self::Repr)
        ensures
            Self::value_of(*r) == Self::value_of(*old(r)),
            Self::tag_of(*r) == true;

    /// Clear the tag bit. Value is preserved.
    fn clear_tag(r: &mut Self::Repr)
        ensures
            Self::value_of(*r) == Self::value_of(*old(r)),
            Self::tag_of(*r) == false;
}

// ---------------------------------------------------------------------------
// `BoolPair<T>` — the canonical `(bool, T)` repr as a named struct.
//
// Verus's trait-conflict checker doesn't like tuple-typed associated types
// here, so we use a named struct. Layout-wise this is exactly `(bool, T)`.
// ---------------------------------------------------------------------------

#[derive(Copy, Clone)]
pub struct BoolPair<T: Copy> {
    pub tag: bool,
    pub value: T,
}

// ---------------------------------------------------------------------------
// Primitive integer impls — `BoolPair<$T>` repr.
// ---------------------------------------------------------------------------

impl Tagged for u8 {
    type Repr = BoolPair<u8>;
    open spec fn value_of(r: Self::Repr) -> Self { r.value }
    open spec fn tag_of(r: Self::Repr) -> bool { r.tag }
    fn into_repr(self) -> Self::Repr { BoolPair { tag: false, value: self } }
    fn from_repr(r: &Self::Repr) -> Self { r.value }
    fn tag(r: &Self::Repr) -> bool { r.tag }
    fn set_tag(r: &mut Self::Repr) { r.tag = true; }
    fn clear_tag(r: &mut Self::Repr) { r.tag = false; }
}

impl Tagged for u16 {
    type Repr = BoolPair<u16>;
    open spec fn value_of(r: Self::Repr) -> Self { r.value }
    open spec fn tag_of(r: Self::Repr) -> bool { r.tag }
    fn into_repr(self) -> Self::Repr { BoolPair { tag: false, value: self } }
    fn from_repr(r: &Self::Repr) -> Self { r.value }
    fn tag(r: &Self::Repr) -> bool { r.tag }
    fn set_tag(r: &mut Self::Repr) { r.tag = true; }
    fn clear_tag(r: &mut Self::Repr) { r.tag = false; }
}

impl Tagged for u32 {
    type Repr = BoolPair<u32>;
