// SPDX-License-Identifier: Apache-2.0
//! `DiffStore`: the capture-protocol contract.
//!
//! A storage backend exposes two ghost views:
//!   - `data: Seq<T>`     — the abstract sequence of stored values
//!   - `captured: Seq<bool>` — per-slot "has been logged this frame" flag
//!
//! Plus a well-formedness predicate `wf()` that ties the two together
//! (e.g. equal lengths, plus any backend-specific invariants).
//!
//! The capture protocol — first-write-wins:
//!   - `prepare_mark(saved_len, prev_diffs)` clears `captured[0..saved_len]`
//!   - `set_raw(i, v)` overwrites `data[i]`; `captured` unchanged
//!   - `capture(i, saved_len, log)` if `i < saved_len && !captured[i]`,
//!       appends `(data[i], i)` to `log` and sets `captured[i] = true`
//!   - `force_capture` like capture but unconditional (used for `pop`)
//!   - `restore_entry(i, old, target_saved_len)` rewinds `data[i]` to `old`
//!     for slots within `[0, target_saved_len)` (and re-pushes if missing
//!     because of a prior pop/truncate cycle)
//!   - `finish_restore(diffs, saved_len)` rebuilds `captured` from the
//!     surviving diff suffix
//!
//! Both `ParallelStore` and `InlineStore` will be proved to satisfy this
//! contract (M2). `Vec`'s proof talks only to `DiffStore`'s contract,
//! so it's parametric in storage.

use vstd::prelude::*;

use crate::index_like::IndexLike;

verus! {

/// Storage backend for the semi-persistent vector.
///
/// Diff entries are `(T, I)` pairs. Methods are no-ops when `TRACK == false`,
/// per the production design; that is reflected in the contracts below.
pub trait DiffStore<T, I, const TRACK: bool>: Sized
where
    T: Sized + Copy,
    I: IndexLike,
{
    // -- ghost views ---------------------------------------------------------

    /// The abstract sequence of stored values. `data().len()` is the exec
    /// length; element types match the user-facing `T`, with any tag-bit
    /// edits projected out.
    spec fn data(&self) -> Seq<T>;

    /// Per-slot capture flag. `captured().len() >= data().len()`.
    /// (Backends may keep stale trailing entries; the only ones that matter
    /// are the prefix `[0..data().len())`.)
    spec fn captured(&self) -> Seq<bool>;

    /// Backend-specific well-formedness. At minimum:
    ///   - `captured().len() >= data().len()`
    ///   - all index access through methods stays within `data()`'s bounds.
    spec fn wf(&self) -> bool;

    // -- raw read / write API ------------------------------------------------

    fn is_empty(&self) -> (b: bool)
        requires self.wf()
        ensures b == (self.data().len() == 0);

    fn len(&self) -> (n: I)
        requires self.wf()
        ensures n.as_nat() == self.data().len();

    fn get(&self, i: I) -> (v: T)
        requires
            self.wf(),
            i.as_nat() < self.data().len(),
        ensures v == self.data()[i.as_nat() as int];

    fn push(&mut self, value: T)
        requires old(self).wf()
        ensures
            self.wf(),
            self.data() == old(self).data().push(value),
            // captured grows by one slot (new slot is uncaptured)
            self.captured().len() == old(self).captured().len() + 1
                || self.captured().len() == old(self).captured().len(),
            // existing capture flags survive
            forall|j: int| 0 <= j < old(self).captured().len()
                ==> #[trigger] self.captured()[j] == old(self).captured()[j];

    fn pop(&mut self) -> (r: Option<T>)
        requires old(self).wf()
        ensures
            self.wf(),
            old(self).data().len() == 0 ==> r is None && self.data() == old(self).data(),
            old(self).data().len() > 0 ==> {
                &&& r is Some
                &&& r->Some_0 == old(self).data()[old(self).data().len() - 1]
                &&& self.data() == old(self).data().drop_last()
            };

    fn set_raw(&mut self, i: I, value: T)
        requires
            old(self).wf(),
            i.as_nat() < old(self).data().len(),
        ensures
            self.wf(),
            self.data() == old(self).data().update(i.as_nat() as int, value),
            self.captured() == old(self).captured();

    fn truncate(&mut self, len: I)
        requires
            old(self).wf(),
            len.as_nat() <= old(self).data().len(),
        ensures
            self.wf(),
            self.data() == old(self).data().subrange(0, len.as_nat() as int);

    // -- capture protocol ----------------------------------------------------
    //
    // When TRACK==false these are total no-ops on observable state; we do not
    // need to express that in the contract since the consumers (Vec) gate the
    // calls behind `TRACK` and never look at `captured()` in that mode.

    fn prepare_mark(&mut self, saved_len: I, prev_diffs: &Seq<(T, I)>)
        requires old(self).wf()
        ensures
            self.wf(),
            self.data() == old(self).data();

    fn capture(&mut self, i: I, saved_len: I, diff_log: &mut Seq<(T, I)>)
        requires
            old(self).wf(),
            i.as_nat() < old(self).data().len(),
        ensures
            self.wf(),
            self.data() == old(self).data();

    fn force_capture(&mut self, i: I, saved_len: I, diff_log: &mut Seq<(T, I)>)
        requires
            old(self).wf(),
            i.as_nat() < old(self).data().len(),
        ensures
            self.wf(),
            self.data() == old(self).data();

    fn restore_entry(&mut self, index: I, old_value: &T, target_saved_len: I)
        requires old(self).wf()
        ensures self.wf();

    fn finish_restore(&mut self, current_frame_diffs: &Seq<(T, I)>, saved_len: I)
        requires old(self).wf()
        ensures
            self.wf(),
            self.data() == old(self).data();

    // -- maintenance ---------------------------------------------------------

    fn shrink_if(&mut self, factor: usize, headroom: usize)
        requires old(self).wf()
        ensures
            self.wf(),
            self.data() == old(self).data();
}

} // verus!

