impl IndexLike for usize {
    open spec fn as_nat(self) -> nat { self as nat }
    // We model `usize::MAX + 1` abstractly via `usize::MAX as nat + 1`. On a
    // 64-bit host this matches `u64::max_nat`; on a 32-bit host it matches
    // `u32::max_nat`. The `lemma_as_nat_bounded` axiom ties it to the host.
    open spec fn max_nat() -> nat { usize::MAX as nat + 1 }
    open spec fn zero_spec() -> Self { 0usize }

    proof fn lemma_as_nat_bounded(self) {}
    proof fn lemma_as_nat_injective(a: Self, b: Self) {}
