    // -- proof obligations ---------------------------------------------------

    /// Every value of `Self` projects to a nat strictly below `max_nat()`.
    proof fn lemma_as_nat_bounded(self)
        ensures self.as_nat() < Self::max_nat();

    /// `as_nat` is injective: distinct values project to distinct nats.
