        requires a.as_nat() == b.as_nat()
        ensures a == b;

    /// `min_spec()` projects to 0.
    proof fn lemma_min_as_nat()
        ensures Self::min_spec().as_nat() == 0;

    /// `max_spec()` projects to `max_nat() - 1` (the maximum representable).
