        ensures Self::max_spec().as_nat() == (Self::max_nat() - 1) as nat;

    // -- exec API ------------------------------------------------------------

    /// Exec: zero / minimum value.
    fn min() -> (r: Self)
        ensures r == Self::min_spec();

    /// Exec: maximum value.
